import React from "react";

function Contact() {
  return (
    <div className="section">
      <h2>Contact Us</h2>
      <p>Email: info@paradiseresort.com</p>
      <p>Phone: +91 98765 43210</p>
      <p>Location: Goa, India</p>
    </div>
  );
}

export default Contact;
